#!/bin/bash
sed -i 's/def generate_eidos_response_worker(bot, chat_id, uid, analysis_type, charge_id=None, amount=None):/def generate_eidos_response_worker(bot, chat_id, uid, analysis_type, charge_id=None, amount=None):\n    logging.info(f"AI Worker started for UID {uid} (Analysis Type: {analysis_type})")/g' modules/services/ai_worker.py
sed -i 's/result_text = sanitize_for_telegram(result_text)/result_text = sanitize_for_telegram(result_text)\n            logging.info(f"AI Worker successfully generated response for UID {uid}")/g' modules/services/ai_worker.py
sed -i 's/def generate_eidos_voice_worker(bot, chat_id, uid, user_text=None, charge_id=None, amount=None):/def generate_eidos_voice_worker(bot, chat_id, uid, user_text=None, charge_id=None, amount=None):\n    logging.info(f"AI Worker started for UID {uid} (Voice Request)")/g' modules/services/ai_worker.py
sed -i 's/artifact_lore = sanitize_for_telegram(parts\[1\].strip())/artifact_lore = sanitize_for_telegram(parts[1].strip())\n                logging.info(f"AI Worker successfully generated response for UID {uid}")/g' modules/services/ai_worker.py
sed -i 's/def generate_user_dossier_worker(bot, chat_id, uid, target_user_data, loading_msg_id=None, refund_bc=None):/def generate_user_dossier_worker(bot, chat_id, uid, target_user_data, loading_msg_id=None, refund_bc=None):\n    logging.info(f"AI Worker started for UID {uid} (User Dossier: {target_user_data.get('\''uid'\'')})")/g' modules/services/ai_worker.py
sed -i 's/ai_text = sanitize_for_telegram(ai_text)/ai_text = sanitize_for_telegram(ai_text)\n            logging.info(f"AI Worker successfully generated response for UID {uid}")/g' modules/services/ai_worker.py
